var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카, 이쪽이 맞나요?","JPN":"ミカさん、こちらで合っていますか？","ENG":"Is this the right way, Mika?","TWN":"米卡，是這裡嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 아마도요. 확신은 못하겠지만요.","JPN":"はい、おそらく。でも確信はできません。","ENG":"I-I think so? I can't say I'm a hundred percent sure though.","TWN":"嗯，應該是吧？我也無法確定。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"에너지 공급장치를 파괴한 직후에 서윤 양과 통신이 두절됐습니다.","JPN":"エネルギー供給装置を破壊した直後、シズカさんと通信が途絶えました。","ENG":"We lost contact with Seo Yoon immediately after destroying the power supply.","TWN":"破壞動能補給裝置後就一直無法和徐芸通訊。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 학생도, 코핀 함과도 연락이 되지 않고 있어요.","JPN":"ミナさんとも、コフィン艦とも連絡が取れない状況です。","ENG":"We cannot get in touch with Mina or the Coffin ship either.","TWN":"米娜同學和科芬艦也是，完全都聯絡不上。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"상황을 파악하려면 한시라도 서둘러 합류지점으로 가야 합니다.","JPN":"状況を把握するためにも、一刻も早く合流地点に向かわなければなりません。","ENG":"We must hurry to the rendezvous point to better ascertain the situation.","TWN":"必須趕快想辦法到集合地點釐清楚狀況才行。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 저희가 왔던 길은 전부 막혀버린 걸요…….","JPN":"でも、私たちが来た道は全部塞がれてしまいました……","ENG":"But the path we took is all blocked off…","TWN":"問題是我們來的路都被堵住了……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래요. 이 일대의 공간 구조가 인위적으로 조작된 모양이에요.","JPN":"そうですね。この一帯の空間構造が人為的に操作されたようです。","ENG":"Indeed. It seems that the spatial structure in this area has been artificially manipulated.","TWN":"是的，這一帶的空間結構似乎有經過人為操作的感覺。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"공간을 조작해요? 이렇게 넓은데요?","JPN":"空間を操作するんですか？　こんなに広いのに？","ENG":"Spatial manipulation? But this place is huge!","TWN":"操作空間？這裡這麼大欸？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 허공에 나타난 저 일그러짐이 보이죠? 공간 균열의 영향이에요.","JPN":"はい。空中に現れたあの歪みが見えますか？　あれは空間亀裂の影響です。","ENG":"Yes. See how there's warping in that empty space over there? That is the impact of spatial rift.","TWN":"對，有看那個扭曲的地方嗎？就是因為受到空間裂縫的影響。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥. 고작 길을 좀 돌아가게 만든 것 가지고 호들갑은.","JPN":"ふん。ちょっと遠回りさせられただけでこんなに騒いじゃって。","ENG":"Hmph. Stop making such a big deal out of taking the long way back.","TWN":"唉唷～不過就是繞了一點路在那邊該該叫！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이런 잔재주에 당황해서야 내 발뒷꿈치나 따라올 수 있겠어?","JPN":"この程度の小細工に慌ててちゃあ、私について来れないわよ？","ENG":"You'll never catch up to me if you let such parlor tricks startle you.","TWN":"才這一點小把戲就把你們嚇到啦？你們會拖累我欸！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"야, 넌 이게 잔재주로 보여?","JPN":"ねえ、あなたにはこれが小細工に見えるの？","ENG":"Does this look like parlor tricks to you?","TWN":"你說這是小把戲？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"다큐멘터리에나 나오는 안토노프 장군님 정도가 아니면 이런 건 엄두도 못낼걸?","JPN":"ドキュメンタリーに出てくるアントノフ将軍ぐらいじゃないと、普通ここまでできないよ？","ENG":"It'll take at least General Antonov from those documentaries to attempt anything like this!","TWN":"對大衛考柏菲來說才是小把戲吧？你哪位？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그래 봤자 어차피 보조기잖아.","JPN":"だってこんなの、どうせ補助スキルでしょ。","ENG":"Yeah, but it's just a supporting skill.","TWN":"反正就是手法嘛！"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"모름지기 기술이란 일격에 적을 해치우는 필살기가 제일이지!","JPN":"技と言うならやっぱり一撃で敵を倒す必殺技が一番強いでしょ！","ENG":"You know what's really badass? Skills that can take out the enemy in a single blow!","TWN":"要說到手法，可以一擊揍扁敵人的必殺技才是最強的吧！"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어휴, 내가 말을 말아야지…….","JPN":"はあ、言うだけ無駄だったわ……","ENG":"Ugh, why do I bother…","TWN":"天啊，我心好累……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"최면에 걸렸다고 해도 사람이 이렇게 바보가 될 수 있는 건가?","JPN":"催眠にかかったとはいえ、人ってあんなバカになるの？","ENG":"Sure, she's under hypnosis, but can anyone really be this stupid?","TWN":"人被催眠後腦袋會變笨嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};